const issues = $input.all().map(i => i.json);

// ai-implementing 라벨이 있어도 PR이 없으면 재처리 (중단된 파이프라인 재개)
const pending = issues.filter(issue => {
  const labelNames = (issue.labels || []).map(l => l.name);
  // PR이 연결된 이슈는 이미 완료된 것 → 건너뜀
  // ai-implementing만 있고 PR 없음 → 중단된 것 → 재처리
  // ai-implementing 없음 → 새 이슈 → 처리
  const hasPrLabel = labelNames.includes('ai-pr-created');
  return !hasPrLabel;
});

if (pending.length === 0) {
  return [{ json: { hasIssue: false } }];
}
const issue = pending[0];
return [{
  json: {
    hasIssue: true,
    issueNumber: issue.number,
    issueTitle: issue.title,
    issueBody: issue.body || '(설명 없음)',
    issueUrl: issue.html_url,
    repoOwner: 'bae080311',
    repoName: 'jump-section'
  }
}]);

const issueInfo = $('Issue 정보 추출').first().json;
const smFile = $('GitHub: ScrollManager.ts 읽기').first().json;
const indexFile = $('GitHub: index.ts 읽기').first().json;

const smContent = Buffer.from(smFile.content.replace(/\n/g, ''), 'base64').toString('utf8');
const indexContent = Buffer.from(indexFile.content.replace(/\n/g, ''), 'base64').toString('utf8');

// 입력 크기 제한: 너무 크면 출력 토큰 부족으로 function call이 잘림
const smTruncated = smContent.length > 8000 ? smContent.slice(0, 8000) + '\n// ... (truncated)' : smContent;

const userPrompt = `## Issue #${issueInfo.issueNumber}: ${issueInfo.issueTitle}\n\n${issueInfo.issueBody}\n\n---\n\n### packages/core/src/ScrollManager.ts\n\`\`\`typescript\n${smTruncated}\n\`\`\`\n\n### packages/core/src/index.ts\n\`\`\`typescript\n${indexContent}\n\`\`\`\n\nwrite_file 함수를 반드시 호출해 구현하세요. 테스트 파일도 포함하세요.`;

const geminiPayload = {
  system_instruction: {
    parts: [{ text: 'TypeScript 전문 개발자입니다. jump-section 라이브러리 신기능을 구현합니다.\nPrettier(2sp, 세미콜론, 싱글쿼트, printWidth 100), strict 타입, Public API 하위 호환 유지.\n반드시 write_file 함수만 사용해 결과를 제출하세요. 텍스트로 코드를 출력하지 마세요.' }]
  },
  contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
  tools: [{
    functionDeclarations: [{
      name: 'write_file',
      description: '수정하거나 새로 생성할 파일의 전체 내용을 제출합니다.',
      parameters: {
        type: 'OBJECT',
        properties: {
          path: { type: 'STRING', description: '파일 경로' },
          content: { type: 'STRING', description: '파일 전체 내용' },
          description: { type: 'STRING', description: '변경 설명' }
        },
        required: ['path', 'content', 'description']
      }
    }]
  }],
  toolConfig: { functionCallingConfig: { mode: 'ANY', allowedFunctionNames: ['write_file'] } },
  generationConfig: {
    maxOutputTokens: 16384,
    thinkingConfig: { thinkingBudget: 0 }
  }
};

return [{
  json: {
    ...issueInfo,
    scrollManagerSha: smFile.sha,
    indexSha: indexFile.sha,
    geminiPayload
  }
}];

const response = $input.first().json;
const issueInfo = $('파일 내용 디코딩').first().json;

// 응답 구조 검증
if (!response.candidates || response.candidates.length === 0) {
  throw new Error('Gemini candidates 없음. 전체 응답: ' + JSON.stringify(response).slice(0, 500));
}

const candidate = response.candidates[0];
const finishReason = candidate.finishReason;

if (!candidate.content) {
  throw new Error(`Gemini content 없음. finishReason: ${finishReason}. 전체 응답: ` + JSON.stringify(candidate).slice(0, 500));
}

const parts = candidate.content.parts;
const functionCalls = parts.filter(p => p.functionCall && p.functionCall.name === 'write_file');
if (functionCalls.length === 0) {
  const textParts = parts.filter(p => p.text).map(p => p.text).join(' ');
  throw new Error(`write_file 함수 미사용. finishReason: ${finishReason}. 텍스트: ${textParts.slice(0, 300)}`);
}

const files = functionCalls.map(p => ({
  path: p.functionCall.args.path,
  content: p.functionCall.args.content,
  description: p.functionCall.args.description
}));

const safeName = issueInfo.issueTitle
  .toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 40);
const branchName = `ai/issue-${issueInfo.issueNumber}-${safeName}`;

return [{
  json: {
    files,
    branchName,
    issueNumber: issueInfo.issueNumber,
    issueTitle: issueInfo.issueTitle,
    issueUrl: issueInfo.issueUrl,
    repoOwner: issueInfo.repoOwner,
    repoName: issueInfo.repoName,
    scrollManagerSha: issueInfo.scrollManagerSha,
    indexSha: issueInfo.indexSha,
    filesSummary: files.map(f => `• \`${f.path}\`: ${f.description}`).join('\n')
  }
}];

const data = $('Tool Use 결과 파싱').first().json;
return data.files.map(file => {
  // 제어 문자 제거 (줄바꿈, 탭 등이 JSON을 깨뜨림)
  const desc = (file.description || '').replace(/[\x00-\x1F\x7F]/g, ' ').trim().slice(0, 72);
  const content = (file.content || '').replace(/\r/g, '\n');
  return {
    json: {
      filePath: (file.path || '').trim(),
      repoOwner: data.repoOwner,
      repoName: data.repoName,
      commitMessage: `feat: implement issue #${data.issueNumber} - ${desc}`,
      commitContent: Buffer.from(content).toString('base64'),
      commitBranch: data.branchName
    }
  };
});

