const getResp = $input.item.json;
const fileData = $('파일 목록 분리').item.json;
const sha = getResp.sha || null;

const bodyObj = {
  message: fileData.commitMessage,
  content: fileData.commitContent,
  branch: fileData.commitBranch
};
if (sha) bodyObj.sha = sha;

// JSON.stringify가 모든 제어 문자를 올바르게 이스케이프
return [{
  json: {
    filePath: fileData.filePath,
    repoOwner: fileData.repoOwner,
    repoName: fileData.repoName,
    hasSha: !!sha,
    commitBodyJson: JSON.stringify(bodyObj)
  }
}];

const https = require('https');
const fileData = $input.item.json;

function httpsRequest(url, options, body) {
  return new Promise((resolve, reject) => {
    const u = new URL(url);
    const req = https.request({
      hostname: u.hostname,
      path: u.pathname,
      method: options.method,
      headers: options.headers
    }, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(data) }));
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const filePath = fileData.filePath.split('/').map(encodeURIComponent).join('/');
const url = `https://api.github.com/repos/${fileData.repoOwner}/${fileData.repoName}/contents/${filePath}`;

const result = await httpsRequest(url, {
  method: 'PUT',
  headers: {
    'Accept': 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28',
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${process.env.GITHUB_TOKEN}`,
    'Content-Length': Buffer.byteLength(fileData.commitBodyJson)
  }
}, fileData.commitBodyJson);

if (result.status < 200 || result.status >= 300) {
  throw new Error(`파일 커밋 실패 (${result.status}): ${JSON.stringify(result.body).slice(0, 300)}`);
}
return [{ json: { path: fileData.filePath, sha: result.body.content?.sha } }];

const https = require('https');
const issueInfo = $('Issue 정보 추출').first().json;

function githubRequest(method, path, body) {
  return new Promise((resolve) => {
    const bodyStr = body ? JSON.stringify(body) : null;
    const req = https.request({
      hostname: 'api.github.com',
      path,
      method,
      headers: {
        'Accept': 'application/vnd.github+json',
        'X-GitHub-Api-Version': '2022-11-28',
        'Authorization': `Bearer ${process.env.GITHUB_TOKEN}`,
        'User-Agent': 'n8n',
        ...(bodyStr ? { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } : {})
      }
    }, res => { res.resume(); res.on('end', () => resolve(res.statusCode)); });
    req.on('error', () => resolve(0));
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

const { repoOwner, repoName, issueNumber } = issueInfo;
const base = `/repos/${repoOwner}/${repoName}/issues/${issueNumber}`;

// 완료 표시 라벨 추가 후 처리 중 라벨 제거
await githubRequest('POST', `${base}/labels`, { labels: ['ai-pr-created'] });
await githubRequest('DELETE', `${base}/labels/ai-implementing`);
await githubRequest('DELETE', `${base}/labels/ai-implement`);

return [{ json: { ...$input.first().json, labelsRemoved: true } }];
